import type { Env, WorkspaceDeploymentStatus } from '../types.js';

export type WorkspaceDeployProviderName = 'simulated' | 'cloudflare_workers_assets';

export interface WorkspaceDeployProviderPrecheck {
  code: string;
  ok: boolean;
  details?: string;
}

export interface WorkspaceDeployCreateInput {
  workspaceId: string;
  deploymentId: string;
  outputDir: string;
  outputBundle: {
    bytes: Uint8Array;
    sha256: string;
  };
}

import { strict as assert } from 'assert';
import {
  createWorkspaceDeployProvider,
  getWorkspaceDeployProviderConfigError,
  getWorkspaceDeployProviderName,
  normalizeProviderError,
  setWorkspaceDeployProviderFetchForTests,
} from './workspace-deploy-provider.js';

export async function runWorkspaceDeployProviderTests(): Promise<void> {
  {
    const provider = createWorkspaceDeployProvider('simulated', {} as never);
    const checks = await provider.precheck();
    assert.equal(checks.length > 0, true);
    const created = await provider.createDeployment({
      workspaceId: 'ws_abc12345',
      deploymentId: 'dep_abcd1234',
      outputDir: 'dist',
      outputBundle: { bytes: new Uint8Array([1, 2, 3]), sha256: 'abc' },
    });

import { strict as assert } from 'assert';
import {
  processWorkspaceDeployment,
  runWorkspaceDeploymentInlineWithRetries,
  setWorkspaceDeploymentSandboxResolverForTests,
  shouldRetryWorkspaceDeploymentError,
} from './workspace-deployment-runner.js';
import { setWorkspaceDeployProviderFetchForTests } from './workspace-deploy-provider.js';

function createDeploymentRunnerEnv(options?: {
  failWorkspaceSummaryUpdate?: boolean;
  failWorkspaceSummaryUpdateTimes?: number;
  failRollbackLookup?: boolean;
  failSucceededEventInsertOnce?: boolean;
  failClaimOnce?: boolean;
